namespace sv_a2325a6b650f439ca07312f140f593bd.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// In Blazor Server, "scoped" = one instance per SignalR circuit,
/// so every interactive component in the same circuit shares this instance.
/// </summary>
public sealed class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    /// <summary>
    /// Fired whenever Theme or AccentColor changes.
    /// Interactive components subscribe to this in OnInitialized
    /// and call StateHasChanged() in the handler.
    /// </summary>
    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@* Interactive island — lives in the circuit so it shares the same
   scoped ThemeService as every other interactive component. *@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<span class="badge rounded-pill"
      style="background-color: @ThemeService.AccentColor; color: white;">
    @ThemeService.Theme
</span>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<ThemeMode>())
            {
                var isActive = ThemeService.Theme == mode;
                <button type="button"
                        class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                        style="@(isActive ? $"background-color:{ThemeService.AccentColor};border-color:{ThemeService.AccentColor}" : "")"
                        @onclick="() => ThemeService.Theme = mode">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-3 mb-3">
            <input type="color"
                   class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnColorChanged" />
            <span class="font-monospace">@ThemeService.AccentColor</span>
        </div>

        <p class="text-muted mb-0">
            Current theme: <strong>@ThemeService.Theme</strong> &mdash;
            Accent: <span style="color: @ThemeService.AccentColor; font-weight: bold;">
                @ThemeService.AccentColor
            </span>
        </p>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += HandleThemeChanged;
    }

    private void OnColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    private void HandleThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= HandleThemeChanged;
    }
}

