+namespace sv_a2325a6b650f439ca07312f140f593bd.Services;
+
+public enum ThemeMode
+{
+    Light,
+    Dark,
+    System
+}
+
+/// <summary>
+/// Scoped service that holds per-circuit theme state.
+/// In Blazor Server, "scoped" = one instance per SignalR circuit,
+/// so every interactive component in the same circuit shares this instance.
+/// </summary>
+public sealed class ThemeService
+{
+    private ThemeMode _theme = ThemeMode.System;
+    private string _accentColor = "#0d6efd";
+
+    public ThemeMode Theme
+    {
+        get => _theme;
+        set
+        {
+            if (_theme == value) return;
+            _theme = value;
+            NotifyChanged();
+        }
+    }
+
+    public string AccentColor
+    {
+        get => _accentColor;
+        set
+        {
+            if (_accentColor == value) return;
+            _accentColor = value;
+            NotifyChanged();
+        }
+    }
+
+    /// <summary>
+    /// Fired whenever Theme or AccentColor changes.
+    /// Interactive components subscribe to this in OnInitialized
+    /// and call StateHasChanged() in the handler.
+    /// </summary>
+    public event Action? OnChange;
+
+    private void NotifyChanged() => OnChange?.Invoke();
+}
+

